    print("=" * 70)

    # Header
    print("\n--- HEADER ---")
    if report["header"]:
        print(json.dumps(report["header"], indent=2))

    # Payload
    print("\n--- PAYLOAD ---")
    if report["payload"]:
        print(json.dumps(report["payload"], indent=2, default=str))

    # Standard Claims
    if report.get("standard_claims"):
        print("\n--- STANDARD CLAIMS ---")
        for claim, info in report["standard_claims"].items():
            print(f"  {claim} ({info['description']}): {info['value']}")

    # Custom Claims
    if report.get("custom_claims"):
        print("\n--- CUSTOM CLAIMS ---")
        for claim, value in report["custom_claims"].items():
            print(f"  {claim}: {value}")

    # Timestamps
    if report.get("readable_timestamps"):
        print("\n--- TIMESTAMPS (Human-Readable) ---")
        for label, info in report["readable_timestamps"].items():
            if "error" in info:
                print(f"  {label}: {info['error']} (raw: {info['raw']})")
            else:
                print(f"  {label}: {info['human']} (unix: {info['raw']})")

    # Expiration
    print("\n--- EXPIRATION STATUS ---")
    if report["is_expired"] is True:
        print(f"  ⚠️  EXPIRED — {report['expiration_details']}")
    elif report["is_expired"] is False:
        print(f"  ✅ Valid — {report['expiration_details']}")
    else:
        print("  ❓ No expiration claim found")

    # Signature
    print("\n--- SIGNATURE VERIFICATION ---")
    if report["signature_verified"] is True:
        print("  ✅ Signature is VALID")
    elif report["signature_verified"] is False:
        print("  ❌ Signature is INVALID")
    else:
        print("  ⚠️  Not verified (no secret provided)")

    # Warnings
    if report["warnings"]:
        print("\n--- WARNINGS ---")
        for warning in report["warnings"]:
            print(f"  ⚠️  {warning}")

    # Errors
    if report["errors"]:
        print("\n--- ERRORS ---")
        for error in report["errors"]:
            print(f"  ❌ {error}")

    print("\n" + "=" * 70)


